function.body:
-- Logistice
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Result NUMBER:=1; -- 0=failure
    v_count NUMBER:=0; -- 0=failure
    v_Record_ID VARCHAR2(32);
    v_User_ID VARCHAR2(32):='0';

    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Record RECORD;
    Cur_Lines RECORD;
	Cur_Lines2 RECORD;

    --IF exist error;
    v_LineError NUMBER:=0;
    v_StatusResult VARCHAR(32):='DR';

BEGIN

    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID);
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);

    BEGIN --BODY
        -- Get Parameters
        v_ResultStr:='ReadingParameters';
        FOR Cur_Parameter IN (
            SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date
            FROM AD_PInstance i
                LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID
            WHERE i.AD_PInstance_ID = P_Instance_ID
            ORDER BY p.SeqNo
        ) LOOP
            v_Record_ID := Cur_Parameter.Record_ID;
            v_User_ID := Cur_Parameter.AD_User_ID;
        END LOOP; -- Get Parameter

        FOR Cur_Lines IN (
            SELECT sccrt_card_load_line_id, fin_finacc_transaction_id
            FROM sccrt_card_load_line l 
                JOIN sccrt_card_load_transaction t ON t.sccrt_card_load_transaction_id = l.sccrt_card_load_transaction_id
                JOIN fin_finacc_transaction tr ON tr.fin_financial_account_id = t.fin_financial_account_from_id
					--Recap
				    AND ( (l.recap IS NULL OR l.recap = '') OR 
					(l.recap = tr.EM_Ssccr_Recapno) )
				    --Lote
				    AND ( (l.lot IS NULL OR l.lot = '') OR 
					 (l.lot = tr.EM_Ssccr_Lot) )
				    --Cost Center
				    AND ( (l.textcostcenter IS NULL OR l.textcostcenter = '') OR 
					(l.textcostcenter = (SELECT value FROM C_Costcenter WHERE C_Costcenter_id = tr.c_costcenter_id)) )
				    --User
				    AND ( (l.textuser IS NULL OR l.textuser = '') OR 
					(l.textuser = (SELECT value FROM user1 WHERE user1_id = tr.user1_id)) )
					--Amount
				    AND (l.amount = tr.depositamt)
            WHERE t.sccrt_card_load_transaction_id = v_Record_ID 
			-- Type
			AND tr.trxtype = 'BPD'
			-- Reconciled
			AND tr.em_ssccr_reconciled = 'N'
			-- N0 Reconciled
			AND coalesce (tr.em_ssccr_Pos_Card_Rec_id, '') = ''
        ) LOOP
            UPDATE sccrt_card_load_line
            SET updated = now(),
                updatedby = v_User_ID,
                fin_finacc_transsaction_id = Cur_Lines.fin_finacc_transaction_id
            WHERE sccrt_card_load_line_id = Cur_Lines.sccrt_card_load_line_id;
        END LOOP; -- Get Cur_Lines

		-- First Log in sccrt_card_load_line
		FOR Cur_Lines2 IN (
            SELECT amount, accredit_value, commision_value ,withh_rent, withh_iva, sccrt_card_load_line_id, fin_finacc_transsaction_id
            FROM sccrt_card_load_line l 
                JOIN sccrt_card_load_transaction t ON t.sccrt_card_load_transaction_id = l.sccrt_card_load_transaction_id
            WHERE t.sccrt_card_load_transaction_id = v_Record_ID 
			-- fin_finacc_transaction nulo
			--AND coalesce (l.fin_finacc_transsaction_id, '') = ''
        ) LOOP

			IF Cur_Lines2.amount != (Cur_Lines2.accredit_value + Cur_Lines2.commision_value + Cur_Lines2.withh_rent + Cur_Lines2.withh_iva) THEN
				UPDATE sccrt_card_load_line
	            SET log_error = 'El monto a liquidar no coincide con el valor de la Transaccion',
				iserror = 'Y',
				fin_finacc_transsaction_id = null
	            WHERE sccrt_card_load_line_id = Cur_Lines2.sccrt_card_load_line_id;
			ELSEIF coalesce (Cur_Lines2.fin_finacc_transsaction_id, '') = '' THEN
				UPDATE sccrt_card_load_line
	            SET log_error = 'No se ha hecho match con ninguna Transaccion',
				iserror = 'Y'
	            WHERE sccrt_card_load_line_id = Cur_Lines2.sccrt_card_load_line_id;
			End IF;

        END LOOP;
		-- End Log sccrt_card_load_line

		-- Verify If Exist Error on Lines
		Select Count(*) Into v_LineError From sccrt_card_load_line 
		Where sccrt_card_load_transaction_id = v_Record_ID
		AND (iserror = 'Y' OR (coalesce(fin_finacc_transsaction_id,'') = ''));

		If (v_LineError = 0 ) THEN
			v_StatusResult:= 'GE';
		ELSEIF v_LineError > 0 THEN
			v_Message := 'Existen '||v_LineError||' registros con error, corrija y vuelva a cargar.';
		End IF;

		--RAISE_APPLICATION_ERROR(-20000,'Errores:'||v_LineError) ;

        UPDATE sccrt_card_load_transaction
        SET updated = now(),
            updatedby = v_User_ID,
            docstatus = v_StatusResult
        FROM (
            SELECT COUNT(*) as haslines, sccrt_card_load_transaction_id
            FROM sccrt_card_load_line
            WHERE fin_finacc_transsaction_id IS NOT NULL 
                AND sccrt_card_load_transaction_id = v_Record_ID
            GROUP BY sccrt_card_load_transaction_id
        ) two
        WHERE sccrt_card_load_transaction.sccrt_card_load_transaction_ID = two.sccrt_card_load_transaction_id
            AND COALESCE(two.haslines, 0) > 0;

        DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message);
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', v_Result, v_Message);

        RETURN;
    END; --BODY

    EXCEPTION WHEN OTHERS THEN
        v_ResultStr:= '@ERROR=' || SQLERRM;
        DBMS_OUTPUT.PUT_LINE( v_ResultStr) ;
        ROLLBACK;
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', 0, v_ResultStr);
END SCCRT_MATCH_LINES
